import heapq
from collections import Counter
class Solution:
    def minCost(self, basket1, basket2):
        n = len(basket1)
        total = basket1 + basket2
        c1 = Counter(basket1)
        c2 = Counter(basket2)
        for key in set(c1) | set(c2):
            if (c1.get(key, 0) - c2.get(key, 0)) % 2 != 0:
                return -1
        total_counter = Counter(total)
        def complement(b1):
            rem = Counter(total_counter)
            rem.subtract(Counter(b1))
            out = []
            for v, c in rem.items():
                out.extend([v] * c)
            return tuple(sorted(out))
        start = tuple(sorted(basket1))
        dist = {start: 0}
        pq = [(0, start)]
        while pq:
            d, b1 = heapq.heappop(pq)
            if d > dist.get(b1, float('inf')):
                continue
            b2 = complement(b1)
            if b1 == b2:
                return d
            b1_list = list(b1)
            for i in range(n):
                for j in range(n):
                    cost = min(b1_list[i], b2[j])
                    nb1 = b1_list[:]
                    nb1[i] = b2[j]
                    nb1_t = tuple(sorted(nb1))
                    nd = d + cost
                    if nd < dist.get(nb1_t, float('inf')):
                        dist[nb1_t] = nd
                        heapq.heappush(pq, (nd, nb1_t))
        return -1

