from collections import Counter
class Solution:
    def minCost(self, basket1, basket2):
        c1 = Counter(basket1)
        c2 = Counter(basket2)
        diff = []
        for key in set(c1) | set(c2):
            d = c1.get(key, 0) - c2.get(key, 0)
            if d % 2 != 0:
                return -1
            half = abs(d) // 2
            if half:
                diff.extend([key] * half)
        if not diff:
            return 0
        diff.sort()
        g = min(min(basket1), min(basket2))
        total = 0
        for i in range(len(diff) // 2):
            total += min(diff[i], 2 * g)
        return total

