var minCost = function(basket1, basket2) {
    const count = new Map();
    for (const x of basket1) count.set(x, (count.get(x) || 0) + 1);
    for (const x of basket2) count.set(x, (count.get(x) || 0) - 1);
    const diff = [];
    for (const [key, d] of count) {
        if (d % 2 !== 0) return -1;
        const half = Math.abs(d) / 2;
        for (let i = 0; i < half; i++) diff.push(key);
    }
    if (diff.length === 0) return 0;
    diff.sort((a, b) => a - b);
    let g = Infinity;
    for (const x of basket1) if (x < g) g = x;
    for (const x of basket2) if (x < g) g = x;
    let total = 0;
    for (let i = 0; i < Math.floor(diff.length / 2); i++) {
        total += Math.min(diff[i], 2 * g);
    }
    return total;
};
